    private fun handleIntent(intent: Intent) {
        if (intent.action == Intent.ACTION_SEND) {
            val type = intent.type
            when {
                "text/plain" == type -> {
                    processTextShare(intent.getStringExtra(Intent.EXTRA_TEXT))
