                type?.startsWith("image/") == true -> {
                    processImageShare(intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM))
                }
                else -> {
                    Timber.w("Unsupported share type: $type")
                }
            }
        } else {
            Timber.w("Invalid intent action: ${intent.action}")
        }
    }

    private fun processTextShare(text: String?) {
